import {Transition} from './Transition';
import {StateMachine} from './StateMachine';
import {TimeoutTransition} from './TimeoutTransition';

import parentLog from './log';
const log = parentLog.createChild("State");

export interface TypedEventLike {
    name: string;
    on: (handle: (x?: any) => void) => any;
    removeListener: (handle: (x?: any) => void) => any;
    emit: (x?: any) => any;
}

interface TypedEventContainer {
    event: TypedEventLike;
    handler: (data?: any) => void;
}

interface EventContainer {
    event: string;
    handler: (data?: any) => void;
}

interface InternalTransition {
    name: string;
    destState: State;
    transition: Transition;
}


export class State {

    public transitions: Transition[] = [];

    /**
     * Method called on entry into the state
     */
    public onEntry: (transition: Transition, result?: any) => any;

    /**
     * Method called on exit from the state
     */
    public onExit: (transition: Transition) => any;

    /**
     * Method called on update from the StateMachine (if it is being called in an update loop)
     */
    public onUpdate: () => void;

    /**
     * Method called if the StateMachine is externally interrupted.
     */
    public onStop: () => any;

    public _isCurrent = false;

    private _lastIncomingResults: any;
    private _entryCounter = 0;
    private _exitCounter = 0;
    private _isExiting = false;
    private _internals: InternalTransition[] = [];
    private _events = new Map<string, EventContainer>();
    private _typedEvents = new Map<TypedEventLike, TypedEventContainer>();
    private _doneTransition: Transition;

    constructor(public sm: StateMachine, public name: string, transitions?: Transition[]) {
        sm._addState(this);
        if (transitions) {
            this.addTransition(transitions);
        }
    }

    addTransition(transitions: Transition[]);
    addTransition(transition: Transition);

    addTransition(transition: any): State {
        if (Array.isArray(transition)) {
            transition.forEach(trans => {
                this._addTransition(trans);
            });
        }
        else {
            this._addTransition(transition);
        }
        return this;
    }

    _addTransition(transition: Transition) {
        if (transition.getSourceState()) {
            this.sm._rejectCurrentPromise(new Error(`This transition has already been assigned to a source state`));
        }

        transition._setSourceState(this);
        this.transitions.push(transition);
    }

    addInternalTransition(name: string, destState: State): State {
        const exists = this._internals.some(i => (i.name === name && i.destState === destState));
        if (exists) {
            throw new Error(`State already has internal transition of name '${name}' to state '${destState.name}'`);
        }

        let internal: InternalTransition = {
            name,
            destState,
            transition: new Transition(name, destState)
        };
        this._internals.push(internal);
        this.addTransition(internal.transition);

        return this;
    }

    addEventTransition(event: string, destState: State): State {
        if (this._events.has(event)) {
            throw new Error(`Duplicate event transition. State: '${this.name}', event: '${event}'`);
        }

        let trans = new Transition('Event: '+event, destState);

        const handler = (result) => {
            if (this._isCurrent) {
                trans.trigger(result);
            }
        };

        this._events.set(event, {event, handler});
        this.addTransition(trans);
        return this;
    }

    addTypedEventTransition(event: TypedEventLike, destState: State): State {
        let trans = new Transition('TEvent: '+event.name, destState);

        const handler = (result) => {
            if (this._isCurrent) {
                trans.trigger(result);
            }
        };

        this._typedEvents.set(event, {event, handler});
        this.addTransition(trans);
        return this;
    }

    addDoneTransition(destState: State) {
        if (this._doneTransition) {
            this.sm._rejectCurrentPromise(new Error(`Done transition for state '${this.name}' already registered`));
        }
        this._doneTransition = new Transition('Done', destState);
        this.addTransition(this._doneTransition);
    }

    async _enter(transition: Transition, result?: any): Promise<any> {
        this._entryCounter++;
        this._isCurrent = true;
        this._lastIncomingResults = result;

        // Here we subscribe to all events
        this._events.forEach(eventCont => {
            this.sm.on(eventCont.event, eventCont.handler);
        });
        this._typedEvents.forEach(eventCont => {
            eventCont.event.on(eventCont.handler);
        });

        // Here we emit the sm transition event since all the state is appropriate at this time
        this.sm.stateChanged.emit(transition);

        // We evaluate this state's onEntry method
        if (this.onEntry) {
            try {
                const ret = this.onEntry(transition, result);

                if (ret instanceof Promise) {
                    // If we have a done transition then we wait on the result from the promise
                    // and pass it into the next state
                    if (this._doneTransition) {
                        const entryCounterThisTime = this._entryCounter;
                        const retFromPromise = await ret;
                        if (this._isCurrent && this._entryCounter === entryCounterThisTime) {
                            this._doneTransition.trigger(retFromPromise);
                        }
                    } else {
                        ret.catch( error => {
                            this.sm._rejectCurrentPromise(error);
                        });
                    }
                } else {
                    if (this._doneTransition) {
                        this._doneTransition.trigger(ret);
                    }
                }
            } catch (e) {
                this.sm._rejectCurrentPromise(e);
            }
        } else {
            if (this._doneTransition) {
                this._doneTransition.trigger(null);
            }
        }

        // We evaluate this state's transitions' onEntry methods
        // There is a chance that we are not current anymore
        if (this._isCurrent) {
            for (let trans of this.transitions) {
                trans._enter();
            }
        }
    }

    _exit(transition: Transition): Promise<any>|void {
        this._isExiting = true;

        // Here we unsubscribe from all events
        this._events.forEach(eventCont => {
            this.sm.removeListener(eventCont.event, eventCont.handler);
        });
        this._typedEvents.forEach(eventCont => {
            eventCont.event.removeListener(eventCont.handler);
        });

        let retPromise: Promise<any>;
        if (this.onExit) {
            try {
                const ret = this.onExit(transition);
                if (ret instanceof Promise) {
                    retPromise = ret as Promise<any>;
                }
            } catch(e) {
                this.sm._rejectCurrentPromise(e);
            }
        }

        for (let trans of this.transitions) {
            trans._exit();
        }

        let exitCleanup = () => {
            this._exitCounter++;
            this._isExiting = false;
            this._isCurrent = false;
        };

        if (retPromise) {
            return retPromise
                .then(exitCleanup)
                .catch(e => this.sm._rejectCurrentPromise(e));
        } else {
            exitCleanup();
        }
    }

    _stop(): Promise<void>|void {
        let retPromise: Promise<any>;

        this.transitions.forEach( trans => {
            if (trans instanceof TimeoutTransition) {
                trans.stop();
            }
        });
        // First we call onStop if it is defined
        if (this.onStop) {
            try {
                const ret = this.onStop();
                if (ret instanceof Promise) {
                    retPromise = (ret as Promise<void>);
                }
            } catch(e) {
                this.sm._rejectCurrentPromise(e);
            }
        }
        if (!this._isExiting && this._exitCounter !== this._entryCounter) {
            // We also call exit
            const finalTransition = new Transition('FINAL TRANSITON', null);
            finalTransition._setSourceState(this);

            let exitRet = this._exit(finalTransition);
            if (exitRet instanceof Promise) {
                const exitRetPr = exitRet as Promise<any>;
                if (retPromise) {
                    retPromise = retPromise.then(() => exitRetPr);
                } else {
                    retPromise = exitRetPr;
                }
            }
        }
        if (retPromise) {
            return retPromise;
        }
    }

    /**
     * Retrieves the last result that was provided to this state upon entry
     * @returns {Object}
     */
    getLastIncomingResult() {
        return this._lastIncomingResults;
    }

    /**
     * Returns whether this is the current state of the state machine
     * @return {boolean}
     */
    isCurrent(): boolean {
        return this._isCurrent;
    }

    /**
     * Transitions to a destination state. An `InternalTransition` needs to
     * have been added from this state to the destination state
     * @param {string} transitionName - The name of the internal transition
     * @param {Object} [result] - Result object to pass to next state
     */
    transitionTo(transitionName: string, result?: any): void;
    /**
     * Transitions to a destination state. An `InternalTransition` needs to
     * have been added from this state to the destination state.
     * When there are outbound transitions of same name then the destination state
     * needs to also be specified
     * @param {string} transitionName - The name of the internal transition
     * @param {State} destState - The desired next state
     * @param {Object} [result] - Result object to pass to next state
     */
    transitionTo(transitionName: string, destState: State, result?: any): void;
    /**
     * Transitions to a destination state. An `InternalTransition` needs to
     * have been added from this state to the destination state
     * @param {State} state The desired next state
     * @param {Object} result Optional result object to pass to next state
     */
    transitionTo(state: State, result?: any): void;
    transitionTo(arg1: State | string, arg2?: any, arg3?: any): void {
        let destState: State;
        let name: string;
        let result: any;

        // If we are being given a transition name
        if (typeof arg1 === 'string') {
            name = arg1;
            if (arg2 instanceof State) {
                destState = arg2;
                result = arg3;
            } else {
                result = arg2;
            }
        }
        else if (arg1 instanceof State) {
            destState = arg1;
            result = arg2;
        }

        // Here we find the internal transition that matches
        const results = this._internals.filter(i => {
            return ((name === undefined) || (name === i.name)) &&
                ((destState === undefined) || (destState === i.destState));
        });

        if (results.length === 0) {
            throw new Error(`State '${this.name}': no internal transition of name '${name}' to state '${destState.name}' found`);
        } else if (results.length > 1) {
            throw new Error(`State '${this.name}': has more than one matching internal transition: '${name}' to state '${destState.name}'`);
        } else {
            const internal = results[0];
            if (!this._isCurrent) {
                let warn = `Attempting internal transition out of a non-current state. ` +
                    `This state: '${this.name}', target state: '${internal.destState.name}', ` +
                    `transition name: '${internal.transition.name}'. `;
                if (this.sm.current) {
                    warn += `Current state: '${this.sm.current.name}'.`;
                } else {
                    warn += `The state machine is currently not running.`;
                }
                log.warn(warn);
            } else {
                internal.transition.trigger(result);
            }
        }
    }

    /**
     * Destroys the state. Should be called when state machine is getting discarded
     */
    destroy(): void {
        // this._isCurrent = false;
        this._events.forEach(eventContainer => {
            this.sm.removeListener(eventContainer.event, eventContainer.handler);
        });
        this._events.clear();
        this._typedEvents.forEach(eventContainer => {
            eventContainer.event.removeListener(eventContainer.handler);
        });
        this._typedEvents.clear();
        this.transitions.forEach( trans => trans.destroy() );
        // this.transitions = [];
        // this._internalTransitions.clear();
        this._lastIncomingResults = null;
        this.onEntry = null;
        this.onExit = null;
        this.onUpdate = null;
        this.onStop = null;
    }

    toString() {
        return 'State: ' + this.name;
    }
}

// For unit tests
(<any>State.prototype).log = log;